&IsErro = false
&Mensagem.SetEmpty()
&MarketPlaceID = '8aec0a32736646889676c911f341768a' 

For Each Order EmpCod, FilCod, CreCod
	Where EmpCod = &EmpCod
	Where FilCod = &FilCod
	Where CreCod = &CreCod
	Where CreRecPag = ReceberPagar.Receber
	Where CreDtaVct >= serverdate()
	Where CreCrbRegAut = Status_SimNao.Sim
	Where CreDtaRet.IsEmpty() or CreDtaRet.IsNull()
	Where not CreCliZoopID.IsEmpty() or not CreCliZoopID.IsNull() 

	&CreDtaVct = CreDtaVct.AddDays(60)//(aaaa-mm-dd)
	&VencimentoVarchar = str(year(CreDtaVct)) +'-'+ padL(str(Month(CreDtaVct)),2, '0') +'-'+ padL(str(Day(CreDtaVct)),2, '0')
	&ExpiracaoVarchar = str(year(&CreDtaVct)) +'-'+ padL(str(Month(&CreDtaVct)),2, '0') +'-'+ padL(str(Day(&CreDtaVct)),2, '0')

	&CreCbrCod = CreCbrCod	
	Do 'GetLocalCobraca'

	&AuxCreBloNro = CreBloNro

	If &ErroCobraca = 0 //Se achou a Chave Master e se achou Chave de Transação (sendo ela a mesma ou criando uma nova) então vai para Emissão
		//########################################### GERA O NOSSO NÚMERO DO BOLETO #####################################	

		If (CreBloNro.IsEmpty() or CreBloNro.IsNull() or CreBloNro.Length() <> 16 or Substr(CreBloNro,1,3) <> '999')  // Duplicata Nosso Número
			&CtaBanNosNro += 1
			GerarNossoNumero.CALL('999',str(EmpCod),&CtaBanNosNro,CreDtaEms,&AuxCreBloNro,&Erro)
			If &Erro = 0
				CreBloNro = trim(&AuxCreBloNro)
				commit
				Do 'GravaNossoNumero'
			EndIf
		EndIf
		//################################################### FIM NOSSO NÚMERO ##########################################

		if CreCliTip = TipoPEssoa.FISICA
			&CpfCnpj = CreCliCpf
		Else
			&CpfCnpj = CreCliCnpj
		Endif
		&CpfCnpj = RetornaSoNumeros.Udp(&CpfCnpj)

		//https://api.zoop.ws//v1/marketplaces/&MarketPlaceID/transactions
		//BOLETO POST
		&reference_id = &AuxCreBloNro
		&ArquivoPost =  '{'
		&ArquivoPost +=  '	"amount":"'+trim(STR((CreVlrDup * 100)))+'",' ////amount: Valor da transação. Transações do tipo boleto devem ser igual ou superior a 300 (R$3,00). Campo obrigatório.
		&ArquivoPost +=  '	"currency": "BRL",' ////currency: Moeda utilizada na transação. Transações do tipo boleto aceitam apenas BRL. Campo obrigatório.
		&ArquivoPost +=  '	"description": "VENDA SISTEMA JASPI",'
		&ArquivoPost +=  '	"reference_id": "'+&reference_id.trim()+'",'
		&ArquivoPost +=  '	"on_behalf_of": "'+&CbrChaMas.Trim()+'",' ////on_behalf_of: Vendedor que receberá pela venda. Campo obrigatório.
		&ArquivoPost +=  '	"customer": "'+CreCliZoopID+'",' //customer: Pagador do boleto. Um pagador pode ser um buyer ou seller. Campo obrigatório.
		&ArquivoPost +=  '	"payment_type": "boleto",' //payment_type: Tipo da transação. Campo obrigatório. 
		//&ArquivoPost +=  '	"logo":	"https://api.zoop.ws/v1/marketplaces/8aec0a32736646889676c911f341768a/custom/file/logo-colored.png",' //logo: Endereço de imagem estática a ser exibida no topo do boleto. Campo opcional.
		&ArquivoPost +=  '	"payment_method": {'
		&ArquivoPost +=  '		"expiration_date": "'+&VencimentoVarchar.Trim()+'",'//expiration_date: Data de expiração do boleto no formato (aaaa-mm-dd). Campo opcional, caso a data de expiração não seja fornecida, o boleto será gerado com vencimento para 3 dias após a data atual.
		&ArquivoPost +=  '		"payment_limit_date": "'+&ExpiracaoVarchar.Trim()+'",'//payment_limit_date: Data limite para o pagamento do boleto (aaaa-mm-dd). Campo opcional.
		//&ArquivoPost +=  '		"body_instructions": ["Pedido #5132"],' //body_instructions: Instruções utilizadas na parte central do boleto. Habitualmente utilizado para descrição da fatura. Ex: "Prestação de serviços de consultoria". 
		&ArquivoPost +=  '		"billing_instructions": {'

		&isVirgula = false
		if &CbrMltVlr > 0
			&Varchar = toformattedString(&CbrMltVlr)
			&Varchar = &Varchar.Replace(',','.')
			&ArquivoPost +=  '			"late_fee": {'//late_fee: Objeto para utilização de cobrança da multa por atraso de pagamento do boleto. Campo opcional.
			&ArquivoPost +=  '				"mode": "PERCENTAGE",'
			&ArquivoPost +=  '				"percentage": '+trim(&Varchar)
			&ArquivoPost +=  '			}'
			&isVirgula = true
		Endif

		if &JurTaxDia > 0
			if &isVirgula = true
				&ArquivoPost +=  ','
			Endif			
			&Varchar = toformattedString(&JurTaxDia)
			&Varchar = &Varchar.Replace(',','.')
			&ArquivoPost +=  '			"interest": {'//interest: Objeto para utilização de cobrança de juros. Campo opcional.
			&ArquivoPost +=  '				"mode": "DAILY_PERCENTAGE",'
			&ArquivoPost +=  '				"percentage": '+trim(&Varchar)
			&ArquivoPost +=  '			}'
			&isVirgula = true
		Endif

		//			&ArquivoPost +=  '			"discount": ['//discount: Objeto para aplicar descontos no boleto para uma ou mais datas limite. Campo opcional. 
		//			&ArquivoPost +=  '			{'
		//			&ArquivoPost +=  '				"mode": "FIXED",'
		//			&ArquivoPost +=  '				"limit_date": "2018-11-09",'
		//			&ArquivoPost +=  '				"amount": 150'
		//			&ArquivoPost +=  '			},'

		//			&ArquivoPost +=  '			{'
		//			&ArquivoPost +=  '				"mode": "FIXED",'
		//			&ArquivoPost +=  '				"limit_date": "2018-11-10",'
		//			&ArquivoPost +=  '				"amount": 100'
		//			&ArquivoPost +=  '			}'
		//			&ArquivoPost +=  '			]'

		&ArquivoPost +=  '		}'
		&ArquivoPost +=  '	}'
		&ArquivoPost +=  '}'

		&ArquivoPost = &ArquivoPost.Replace('	', '')
		&ArquivoPost = &ArquivoPost.Replace('  ', ' ')

		HostWebServiceBoletoApi.Call('',999, &EmpWebHost, &EmpWebBaseUrl, &EmpWebPor) // 999 = zoop pagamentos
		&HttpClient.Host = &EmpWebHost //servidor
		&HttpClient.Secure = 1
		&httpclient.AddHeader(!'Content-type',!'application/json')
		&httpclient.AddHeader('authorization', 'Basic enBrX3Byb2RfQURJcWZCNGFmblZ6Q0trWkRLR0UxTnFvOg==')
		&String = 'v1/marketplaces/'+&MarketPlaceID.trim()+'/transactions'
		&httpclient.AddString(&ArquivoPost)
		csharp System.Net.ServicePointManager.SecurityProtocol = System.Net.SecurityProtocolType.Tls12 | System.Net.SecurityProtocolType.Tls11 | System.Net.SecurityProtocolType.Tls;
		&HttpClient.Execute('POST',&String)

		&sdtZoop_duplicata.FromJson(&HttpClient.toString())

		//padraoUsuario.Call('G', '#REGISTROZOOP_DUP', &WWPContext.PesCod, &EmpCod, &HttpClient.toString(), &PadDtaMod)  // Grava resultado do Post só como um LOG para Consulta
		//padraoUsuario.Call('G', '#REGISTROZOOP_DUP2', &WWPContext.PesCod, &EmpCod, &ArquivoPost, &PadDtaMod)  // Grava PARAMETRO como um LOG para Consulta

	 	//################################# sem erro de comunicação ################################################################################
		Do Case
			Case &HttpClient.ErrCode = 0  //HTTP_CREATED  Operação realizada com sucesso
				&Mensagem = '201 - Registrado com sucesso!'

				&DtRegistroVar = &sdtZoop_duplicata.created_at
				CreDtaRet = yMDtoD(val(substr(&DtRegistroVar,1,4)),val(substr(&DtRegistroVar,6,2)),val(substr(&DtRegistroVar,9,2)))
				//CreCodBar = &SdtRetornoBradesco.cdBarras
				CreLinDig = &sdtZoop_duplicata.payment_method.barcode
				CreArqRetApiEco = &HttpClient.toString()
				commit

				//ImpressaoBoletoApi_Zoop.Call(EmpCod, FilCod, CreCod, &NomeArquivo)
				//CrePdf64ApiEco = 

				//JDF - PERA SO 1 MINUTO
				//ImpressaoBoletoBradesco.call(&EmpCod,&CreCod,&CreCbrCod,&CbrChaTra,&CbrCtaBanAgeCod,&CbrNroCon,str(&SdtRetornoBradesco.nutituloGerado),&CbrCtaBanAgeDig)
			Otherwise
				&Mensagem = 'ERRO - '+trim(str(&HttpClient.ErrCode)) +': '+&HttpClient.ErrDescription
				&IsErro = true
		EndCase
	EndIf

