when none
	&Mensagem = 'Impossível gerar Boleto para esta Duplicata!, a Mesma NÃO pode estar vencida, e deve ser do tipo RECEBER, e com boleto online no local de Cobrança!'
	&IsErro = true
EndFor


Sub 'GetLocalCobraca'
	&ErroCobraca = 0

	For each Order EmpCod,CbrCod
		Where EmpCod = &EmpCod
		Where CbrCod = &CreCbrCod

		&CtaBanNosNro    = CtaBanNosNro

		&CbrDesDia = CbrDesDia
		&CbrQtdDiaDesc = CbrQtdDiaDesc
		&CbrDesAnt  = CbrDesAnt
		&CbrInsBol1 = CbrInsBol1
		&CbrMltVlr  = CbrMltVlr

		If not CbrChaMas.Trim().IsEmpty()  // chave master NÃO esta Vazia?
			&CbrChaMas = CbrChaMas
		Else
			&ErroCobraca = 1
			&Mensagem = 'Chave master no Local de Cobrança inválida, verifique!'
			&IsErro = true
		EndIF
		&CbrJurCod = CbrJurCod// Local Cobrança Juros Código
		&JurTaxDia = 0
		&JurTax = 0
		Do 'Juros'
	EndFor
EndSub

Sub 'GravaNossoNumero'
	For each Order EmpCod,CbrCod,CbrTipImp
		Where EmpCod = &EmpCod
		Where CbrCod = &CreCbrCod
		//Where CbrTipImp = TipoImpressao.GerarBoleto  //Gerar Boleto
		CtaBanNosNro	= &CtaBanNosNro  
		Exit
	EndFor
	Commit	
EndSub

Sub 'Juros'	
	For each Order EmpCod,JurCod,(JurAno),(JurMes)
		Where EmpCod = &EmpCod
		Where JurCod = &CbrJurCod
		&JurTax = JurTax
		if JurTax > 0
			&JurTaxDia = ((JurTax) / 30)
		Endif
		Exit
	EndFor
EndSub
